-            return (lower.startsWith('http://') || lower.startsWith('https://')) &&
-                   (lower.includes('.jpg') || lower.includes('.jpeg') || lower.includes('.png') ||
-                    lower.includes('.gif') || lower.includes('.webp') || lower.includes('.svg'));
-        }
